package com.garnegsoft.hubs

import com.garnegsoft.hubs.ui.screens.article.tts.ArticleContentSplitter
import org.jsoup.Jsoup
import org.junit.Test

class SplitterTests {

    val text = "Вот небольшая история из жизни — но одновременно это история о «синем экране смерти».\n" +
